    36→	"github.com/prometheus/prometheus/tsdb/fileutil"
    37→	"github.com/prometheus/prometheus/tsdb/index"
    38→	"github.com/prometheus/prometheus/tsdb/tombstones"
    39→)
    40→
    41→// ExponentialBlockRanges returns the time ranges based on the stepSize.
    42→func ExponentialBlockRanges(minSize int64, steps, stepSize int) []int64 {
    43→	ranges := make([]int64, 0, steps)
    44→	curRange := minSize
    45→	for i := 0; i < steps; i++ {
    46→		ranges = append(ranges, curRange)
    47→		curRange *= int64(stepSize)
    48→	}
    49→
    50→	return ranges
    51→}
    52→
    53→// Compactor provides compaction against an underlying storage
    54→// of time series data.
    55→type Compactor interface {
    56→	// Plan returns a set of directories that can be compacted concurrently.
    57→	// The directories can be overlapping.
    58→	// Results returned when compactions are in progress are undefined.
    59→	Plan(dir string) ([]string, error)
    60→
    61→	// Write persists a Block into a directory.
    62→	// No Block is written when resulting Block has 0 samples, and returns empty ulid.ULID{}.
    63→	Write(dest string, b BlockReader, mint, maxt int64, base *BlockMeta) (ulid.ULID, error)
    64→
    65→	// Compact runs compaction against the provided directories. Must
    66→	// only be called concurrently with results of Plan().
    67→	// Can optionally pass a list of already open blocks,
    68→	// to avoid having to reopen them.
    69→	// When resulting Block has 0 samples
    70→	//  * No block is written.
    71→	//  * The source dirs are marked Deletable.
    72→	//  * Returns empty ulid.ULID{}.
    73→	Compact(dest string, dirs []string, open []*Block) (ulid.ULID, error)
    74→}
    75→
    76→// LeveledCompactor implements the Compactor interface.
    77→type LeveledCompactor struct {
    78→	metrics                     *CompactorMetrics
    79→	logger                      log.Logger
    80→	ranges                      []int64
    81→	chunkPool                   chunkenc.Pool
    82→	ctx                         context.Context
    83→	maxBlockChunkSegmentSize    int64
    84→	mergeFunc                   storage.VerticalChunkSeriesMergeFunc
    85→	postingsEncoder             index.PostingsEncoder
    86→	enableOverlappingCompaction bool
    87→}
    88→
    89→type CompactorMetrics struct {
    90→	Ran               prometheus.Counter
    91→	PopulatingBlocks  prometheus.Gauge
    92→	OverlappingBlocks prometheus.Counter
    93→	Duration          prometheus.Histogram
    94→	ChunkSize         prometheus.Histogram
    95→	ChunkSamples      prometheus.Histogram
    96→	ChunkRange        prometheus.Histogram
    97→}
    98→
    99→// NewCompactorMetrics initializes metrics for Compactor.
   100→func NewCompactorMetrics(r prometheus.Registerer) *CompactorMetrics {
   101→	m := &CompactorMetrics{}
   102→
   103→	m.Ran = prometheus.NewCounter(prometheus.CounterOpts{
   104→		Name: "prometheus_tsdb_compactions_total",
   105→		Help: "Total number of compactions that were executed for the partition.",
   106→	})
   107→	m.PopulatingBlocks = prometheus.NewGauge(prometheus.GaugeOpts{
   108→		Name: "prometheus_tsdb_compaction_populating_block",
   109→		Help: "Set to 1 when a block is currently being written to the disk.",
   110→	})
   111→	m.OverlappingBlocks = prometheus.NewCounter(prometheus.CounterOpts{
   112→		Name: "prometheus_tsdb_vertical_compactions_total",
   113→		Help: "Total number of compactions done on overlapping blocks.",
   114→	})
   115→	m.Duration = prometheus.NewHistogram(prometheus.HistogramOpts{
   116→		Name:                            "prometheus_tsdb_compaction_duration_seconds",
   117→		Help:                            "Duration of compaction runs",
   118→		Buckets:                         prometheus.ExponentialBuckets(1, 2, 14),
   119→		NativeHistogramBucketFactor:     1.1,
   120→		NativeHistogramMaxBucketNumber:  100,
   121→		NativeHistogramMinResetDuration: 1 * time.Hour,
   122→	})
   123→	m.ChunkSize = prometheus.NewHistogram(prometheus.HistogramOpts{
   124→		Name:    "prometheus_tsdb_compaction_chunk_size_bytes",
   125→		Help:    "Final size of chunks on their first compaction",
   126→		Buckets: prometheus.ExponentialBuckets(32, 1.5, 12),
   127→	})
   128→	m.ChunkSamples = prometheus.NewHistogram(prometheus.HistogramOpts{
   129→		Name:    "prometheus_tsdb_compaction_chunk_samples",
   130→		Help:    "Final number of samples on their first compaction",
   131→		Buckets: prometheus.ExponentialBuckets(4, 1.5, 12),
   132→	})
   133→	m.ChunkRange = prometheus.NewHistogram(prometheus.HistogramOpts{
   134→		Name:    "prometheus_tsdb_compaction_chunk_range_seconds",
   135→		Help:    "Final time range of chunks on their first compaction",
   136→		Buckets: prometheus.ExponentialBuckets(100, 4, 10),
   137→	})
   138→
   139→	if r != nil {
   140→		r.MustRegister(
   141→			m.Ran,
   142→			m.PopulatingBlocks,
   143→			m.OverlappingBlocks,
   144→			m.Duration,
   145→			m.ChunkRange,
   146→			m.ChunkSamples,
   147→			m.ChunkSize,
   148→		)
   149→	}
   150→	return m
   151→}
   152→
   153→type LeveledCompactorOptions struct {
   154→	// PE specifies the postings encoder. It is called when compactor is writing out the postings for a label name/value pair during compaction.
   155→	// If it is nil then the default encoder is used. At the moment that is the "raw" encoder. See index.EncodePostingsRaw for more.
   156→	PE index.PostingsEncoder
   157→	// MaxBlockChunkSegmentSize is the max block chunk segment size. If it is 0 then the default chunks.DefaultChunkSegmentSize is used.
   158→	MaxBlockChunkSegmentSize int64
   159→	// MergeFunc is used for merging series together in vertical compaction. By default storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge) is used.
   160→	MergeFunc storage.VerticalChunkSeriesMergeFunc
   161→	// EnableOverlappingCompaction enables compaction of overlapping blocks. In Prometheus it is always enabled.
   162→	// It is useful for downstream projects like Mimir, Cortex, Thanos where they have a separate component that does compaction.
   163→	EnableOverlappingCompaction bool
   164→}
   165→
   166→func NewLeveledCompactorWithChunkSize(ctx context.Context, r prometheus.Registerer, l log.Logger, ranges []int64, pool chunkenc.Pool, maxBlockChunkSegmentSize int64, mergeFunc storage.VerticalChunkSeriesMergeFunc) (*LeveledCompactor, error) {
   167→	return NewLeveledCompactorWithOptions(ctx, r, l, ranges, pool, LeveledCompactorOptions{
   168→		MaxBlockChunkSegmentSize:    maxBlockChunkSegmentSize,
   169→		MergeFunc:                   mergeFunc,
   170→		EnableOverlappingCompaction: true,
   171→	})
   172→}
   173→
   174→func NewLeveledCompactor(ctx context.Context, r prometheus.Registerer, l log.Logger, ranges []int64, pool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc) (*LeveledCompactor, error) {
   175→	return NewLeveledCompactorWithOptions(ctx, r, l, ranges, pool, LeveledCompactorOptions{
   176→		MergeFunc:                   mergeFunc,
   177→		EnableOverlappingCompaction: true,
   178→	})
   179→}
   180→
   181→func NewLeveledCompactorWithOptions(ctx context.Context, r prometheus.Registerer, l log.Logger, ranges []int64, pool chunkenc.Pool, opts LeveledCompactorOptions) (*LeveledCompactor, error) {
   182→	if len(ranges) == 0 {
   183→		return nil, fmt.Errorf("at least one range must be provided")
   184→	}
   185→	if pool == nil {
   186→		pool = chunkenc.NewPool()
   187→	}
   188→	if l == nil {
   189→		l = log.NewNopLogger()
   190→	}
   191→	mergeFunc := opts.MergeFunc
   192→	if mergeFunc == nil {
   193→		mergeFunc = storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge)
   194→	}
   195→	maxBlockChunkSegmentSize := opts.MaxBlockChunkSegmentSize
   196→	if maxBlockChunkSegmentSize == 0 {
   197→		maxBlockChunkSegmentSize = chunks.DefaultChunkSegmentSize
   198→	}
   199→	pe := opts.PE
   200→	if pe == nil {
   201→		pe = index.EncodePostingsRaw
   202→	}
   203→	return &LeveledCompactor{
   204→		ranges:                      ranges,
   205→		chunkPool:                   pool,
   206→		logger:                      l,
   207→		metrics:                     NewCompactorMetrics(r),
   208→		ctx:                         ctx,
   209→		maxBlockChunkSegmentSize:    maxBlockChunkSegmentSize,
   210→		mergeFunc:                   mergeFunc,
   211→		postingsEncoder:             pe,
   212→		enableOverlappingCompaction: opts.EnableOverlappingCompaction,
   213→	}, nil
   214→}
   215→
   216→type dirMeta struct {
   217→	dir  string
   218→	meta *BlockMeta
   219→}
   220→
   221→// Plan returns a list of compactable blocks in the provided directory.
   222→func (c *LeveledCompactor) Plan(dir string) ([]string, error) {
   223→	dirs, err := blockDirs(dir)
   224→	if err != nil {
   225→		return nil, err
   226→	}
   227→	if len(dirs) < 1 {
   228→		return nil, nil
   229→	}
   230→
   231→	var dms []dirMeta
   232→	for _, dir := range dirs {
   233→		meta, _, err := readMetaFile(dir)
   234→		if err != nil {
   235→			return nil, err
   236→		}
   237→		dms = append(dms, dirMeta{dir, meta})
   238→	}
   239→	return c.plan(dms)
   240→}
   241→
   242→func (c *LeveledCompactor) plan(dms []dirMeta) ([]string, error) {
   243→	slices.SortFunc(dms, func(a, b dirMeta) int {
   244→		switch {
   245→		case a.meta.MinTime < b.meta.MinTime:
   246→			return -1
   247→		case a.meta.MinTime > b.meta.MinTime:
   248→			return 1
   249→		default:
   250→			return 0
   251→		}
   252→	})
   253→
   254→	res := c.selectOverlappingDirs(dms)
   255→	if len(res) > 0 {
   256→		return res, nil
   257→	}
   258→	// No overlapping blocks, do compaction the usual way.
   259→	// We do not include a recently created block with max(minTime), so the block which was just created from WAL.
   260→	// This gives users a window of a full block size to piece-wise backup new data without having to care about data overlap.
   261→	dms = dms[:len(dms)-1]
   262→
   263→	for _, dm := range c.selectDirs(dms) {
   264→		res = append(res, dm.dir)
   265→	}
   266→	if len(res) > 0 {
   267→		return res, nil
   268→	}
   269→
   270→	// Compact any blocks with big enough time range that have >5% tombstones.
   271→	for i := len(dms) - 1; i >= 0; i-- {
   272→		meta := dms[i].meta
   273→		if meta.MaxTime-meta.MinTime < c.ranges[len(c.ranges)/2] {
   274→			// If the block is entirely deleted, then we don't care about the block being big enough.
   275→			// TODO: This is assuming single tombstone is for distinct series, which might be no true.
   276→			if meta.Stats.NumTombstones > 0 && meta.Stats.NumTombstones >= meta.Stats.NumSeries {
   277→				return []string{dms[i].dir}, nil
   278→			}
   279→			break
   280→		}
   281→		if float64(meta.Stats.NumTombstones)/float64(meta.Stats.NumSeries+1) > 0.05 {
   282→			return []string{dms[i].dir}, nil
   283→		}
   284→	}
   285→
   286→	return nil, nil
   287→}
   288→
   289→// selectDirs returns the dir metas that should be compacted into a single new block.
   290→// If only a single block range is configured, the result is always nil.
   291→func (c *LeveledCompactor) selectDirs(ds []dirMeta) []dirMeta {
   292→	if len(c.ranges) < 2 || len(ds) < 1 {
   293→		return nil
   294→	}
   295→
   296→	highTime := ds[len(ds)-1].meta.MinTime
   297→
   298→	for _, iv := range c.ranges[1:] {
   299→		parts := splitByRange(ds, iv)
   300→		if len(parts) == 0 {
   301→			continue
   302→		}
   303→
   304→	Outer:
   305→		for _, p := range parts {
   306→			// Do not select the range if it has a block whose compaction failed.
   307→			for _, dm := range p {
   308→				if dm.meta.Compaction.Failed {
   309→					continue Outer
   310→				}
   311→			}
   312→
   313→			mint := p[0].meta.MinTime
   314→			maxt := p[len(p)-1].meta.MaxTime
   315→			// Pick the range of blocks if it spans the full range (potentially with gaps)
   316→			// or is before the most recent block.
   317→			// This ensures we don't compact blocks prematurely when another one of the same
   318→			// size still fits in the range.
   319→			if (maxt-mint == iv || maxt <= highTime) && len(p) > 1 {
   320→				return p
   321→			}
   322→		}
   323→	}
   324→
   325→	return nil
   326→}
   327→
   328→// selectOverlappingDirs returns all dirs with overlapping time ranges.
   329→// It expects sorted input by mint and returns the overlapping dirs in the same order as received.
   330→func (c *LeveledCompactor) selectOverlappingDirs(ds []dirMeta) []string {
   331→	if !c.enableOverlappingCompaction {
   332→		return nil
   333→	}
   334→	if len(ds) < 2 {
   335→		return nil
   336→	}
   337→	var overlappingDirs []string
   338→	globalMaxt := ds[0].meta.MaxTime
   339→	for i, d := range ds[1:] {
   340→		if d.meta.MinTime < globalMaxt {
   341→			if len(overlappingDirs) == 0 { // When it is the first overlap, need to add the last one as well.
   342→				overlappingDirs = append(overlappingDirs, ds[i].dir)
   343→			}
   344→			overlappingDirs = append(overlappingDirs, d.dir)
   345→		} else if len(overlappingDirs) > 0 {
   346→			break
   347→		}
   348→		if d.meta.MaxTime > globalMaxt {
   349→			globalMaxt = d.meta.MaxTime
   350→		}
   351→	}
   352→	return overlappingDirs
   353→}
   354→
   355→// splitByRange splits the directories by the time range. The range sequence starts at 0.
   356→//
   357→// For example, if we have blocks [0-10, 10-20, 50-60, 90-100] and the split range tr is 30
   358→// it returns [0-10, 10-20], [50-60], [90-100].
   359→func splitByRange(ds []dirMeta, tr int64) [][]dirMeta {
   360→	var splitDirs [][]dirMeta
   361→
   362→	for i := 0; i < len(ds); {
   363→		var (
   364→			group []dirMeta
   365→			t0    int64
   366→			m     = ds[i].meta
   367→		)
   368→		// Compute start of aligned time range of size tr closest to the current block's start.
   369→		if m.MinTime >= 0 {
   370→			t0 = tr * (m.MinTime / tr)
   371→		} else {
   372→			t0 = tr * ((m.MinTime - tr + 1) / tr)
   373→		}
   374→		// Skip blocks that don't fall into the range. This can happen via mis-alignment or
   375→		// by being the multiple of the intended range.
   376→		if m.MaxTime > t0+tr {
   377→			i++
   378→			continue
   379→		}
   380→
   381→		// Add all dirs to the current group that are within [t0, t0+tr].
   382→		for ; i < len(ds); i++ {
   383→			// Either the block falls into the next range or doesn't fit at all (checked above).
   384→			if ds[i].meta.MaxTime > t0+tr {
   385→				break
   386→			}
   387→			group = append(group, ds[i])
   388→		}
   389→
   390→		if len(group) > 0 {
   391→			splitDirs = append(splitDirs, group)
   392→		}
   393→	}
   394→
   395→	return splitDirs
   396→}
   397→
   398→// CompactBlockMetas merges many block metas into one, combining it's source blocks together
   399→// and adjusting compaction level. Min/Max time of result block meta covers all input blocks.
   400→func CompactBlockMetas(uid ulid.ULID, blocks ...*BlockMeta) *BlockMeta {
   401→	res := &BlockMeta{
   402→		ULID: uid,
   403→	}
   404→
   405→	sources := map[ulid.ULID]struct{}{}
   406→	mint := blocks[0].MinTime
   407→	maxt := blocks[0].MaxTime
   408→
   409→	for _, b := range blocks {
   410→		if b.MinTime < mint {
   411→			mint = b.MinTime
   412→		}
   413→		if b.MaxTime > maxt {
   414→			maxt = b.MaxTime
   415→		}
   416→		if b.Compaction.Level > res.Compaction.Level {
   417→			res.Compaction.Level = b.Compaction.Level
   418→		}
   419→		for _, s := range b.Compaction.Sources {
   420→			sources[s] = struct{}{}
   421→		}
   422→		res.Compaction.Parents = append(res.Compaction.Parents, BlockDesc{
   423→			ULID:    b.ULID,
   424→			MinTime: b.MinTime,
   425→			MaxTime: b.MaxTime,
   426→		})
   427→	}
   428→	res.Compaction.Level++
   429→
   430→	for s := range sources {
   431→		res.Compaction.Sources = append(res.Compaction.Sources, s)
   432→	}
   433→	slices.SortFunc(res.Compaction.Sources, func(a, b ulid.ULID) int {
   434→		return a.Compare(b)
   435→	})
   436→
   437→	res.MinTime = mint
   438→	res.MaxTime = maxt
   439→	return res
   440→}
