   587→// instrumentedChunkWriter is used for level 1 compactions to record statistics
   588→// about compacted chunks.
   589→type instrumentedChunkWriter struct {
   590→	ChunkWriter
   591→
   592→	size    prometheus.Histogram
   593→	samples prometheus.Histogram
   594→	trange  prometheus.Histogram
   595→}
   596→
   597→func (w *instrumentedChunkWriter) WriteChunks(chunks ...chunks.Meta) error {
   598→	for _, c := range chunks {
   599→		w.size.Observe(float64(len(c.Chunk.Bytes())))
   600→		w.samples.Observe(float64(c.Chunk.NumSamples()))
   601→		w.trange.Observe(float64(c.MaxTime - c.MinTime))
   602→	}
   603→	return w.ChunkWriter.WriteChunks(chunks...)
   604→}
   605→
   606→// write creates a new block that is the union of the provided blocks into dir.
   607→func (c *LeveledCompactor) write(dest string, meta *BlockMeta, blockPopulator BlockPopulator, blocks ...BlockReader) (err error) {
   608→	dir := filepath.Join(dest, meta.ULID.String())
   609→	tmp := dir + tmpForCreationBlockDirSuffix
   610→	var closers []io.Closer
   611→	defer func(t time.Time) {
   612→		err = tsdb_errors.NewMulti(err, tsdb_errors.CloseAll(closers)).Err()
   613→
   614→		// RemoveAll returns no error when tmp doesn't exist so it is safe to always run it.
   615→		if err := os.RemoveAll(tmp); err != nil {
   616→			level.Error(c.logger).Log("msg", "removed tmp folder after failed compaction", "err", err.Error())
   617→		}
   618→		c.metrics.Ran.Inc()
   619→		c.metrics.Duration.Observe(time.Since(t).Seconds())
   620→	}(time.Now())
   621→
   622→	if err = os.RemoveAll(tmp); err != nil {
   623→		return err
   624→	}
   625→
   626→	if err = os.MkdirAll(tmp, 0o777); err != nil {
   627→		return err
   628→	}
   629→
   630→	// Populate chunk and index files into temporary directory with
   631→	// data of all blocks.
   632→	var chunkw ChunkWriter
   633→
   634→	chunkw, err = chunks.NewWriterWithSegSize(chunkDir(tmp), c.maxBlockChunkSegmentSize)
   635→	if err != nil {
   636→		return fmt.Errorf("open chunk writer: %w", err)
   637→	}
   638→	closers = append(closers, chunkw)
   639→	// Record written chunk sizes on level 1 compactions.
   640→	if meta.Compaction.Level == 1 {
   641→		chunkw = &instrumentedChunkWriter{
   642→			ChunkWriter: chunkw,
   643→			size:        c.metrics.ChunkSize,
   644→			samples:     c.metrics.ChunkSamples,
   645→			trange:      c.metrics.ChunkRange,
   646→		}
   647→	}
   648→
   649→	indexw, err := index.NewWriterWithEncoder(c.ctx, filepath.Join(tmp, indexFilename), c.postingsEncoder)
   650→	if err != nil {
   651→		return fmt.Errorf("open index writer: %w", err)
   652→	}
   653→	closers = append(closers, indexw)
   654→
   655→	if err := blockPopulator.PopulateBlock(c.ctx, c.metrics, c.logger, c.chunkPool, c.mergeFunc, blocks, meta, indexw, chunkw); err != nil {
   656→		return fmt.Errorf("populate block: %w", err)
   657→	}
   658→
   659→	select {
   660→	case <-c.ctx.Done():
   661→		return c.ctx.Err()
   662→	default:
   663→	}
   664→
   665→	// We are explicitly closing them here to check for error even
   666→	// though these are covered under defer. This is because in Windows,
   667→	// you cannot delete these unless they are closed and the defer is to
   668→	// make sure they are closed if the function exits due to an error above.
   669→	errs := tsdb_errors.NewMulti()
   670→	for _, w := range closers {
   671→		errs.Add(w.Close())
   672→	}
   673→	closers = closers[:0] // Avoid closing the writers twice in the defer.
   674→	if errs.Err() != nil {
   675→		return errs.Err()
   676→	}
   677→
   678→	// Populated block is empty, so exit early.
   679→	if meta.Stats.NumSamples == 0 {
   680→		return nil
   681→	}
   682→
   683→	if _, err = writeMetaFile(c.logger, tmp, meta); err != nil {
   684→		return fmt.Errorf("write merged meta: %w", err)
   685→	}
   686→
   687→	// Create an empty tombstones file.
   688→	if _, err := tombstones.WriteFile(c.logger, tmp, tombstones.NewMemTombstones()); err != nil {
   689→		return fmt.Errorf("write new tombstones file: %w", err)
   690→	}
   691→
   692→	df, err := fileutil.OpenDir(tmp)
   693→	if err != nil {
   694→		return fmt.Errorf("open temporary block dir: %w", err)
   695→	}
   696→	defer func() {
   697→		if df != nil {
   698→			df.Close()
   699→		}
   700→	}()
   701→
   702→	if err := df.Sync(); err != nil {
   703→		return fmt.Errorf("sync temporary dir file: %w", err)
   704→	}
   705→
   706→	// Close temp dir before rename block dir (for windows platform).
   707→	if err = df.Close(); err != nil {
   708→		return fmt.Errorf("close temporary dir: %w", err)
   709→	}
   710→	df = nil
   711→
   712→	// Block successfully written, make it visible in destination dir by moving it from tmp one.
   713→	if err := fileutil.Replace(tmp, dir); err != nil {
   714→		return fmt.Errorf("rename block dir: %w", err)
   715→	}
   716→
   717→	return nil
   718→}
   719→
   720→type BlockPopulator interface {
   721→	PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger log.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter) error
   722→}
   723→
   724→type DefaultBlockPopulator struct{}
   725→
   726→// PopulateBlock fills the index and chunk writers with new data gathered as the union
   727→// of the provided blocks. It returns meta information for the new block.
   728→// It expects sorted blocks input by mint.
   729→func (c DefaultBlockPopulator) PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger log.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter) (err error) {
   730→	if len(blocks) == 0 {
   731→		return errors.New("cannot populate block from no readers")
   732→	}
   733→
   734→	var (
   735→		sets        []storage.ChunkSeriesSet
   736→		symbols     index.StringIter
   737→		closers     []io.Closer
   738→		overlapping bool
   739→	)
   740→	defer func() {
   741→		errs := tsdb_errors.NewMulti(err)
   742→		if cerr := tsdb_errors.CloseAll(closers); cerr != nil {
   743→			errs.Add(fmt.Errorf("close: %w", cerr))
   744→		}
   745→		err = errs.Err()
   746→		metrics.PopulatingBlocks.Set(0)
   747→	}()
   748→	metrics.PopulatingBlocks.Set(1)
   749→
   750→	globalMaxt := blocks[0].Meta().MaxTime
   751→	for i, b := range blocks {
   752→		select {
   753→		case <-ctx.Done():
   754→			return ctx.Err()
   755→		default:
   756→		}
   757→
   758→		if !overlapping {
   759→			if i > 0 && b.Meta().MinTime < globalMaxt {
   760→				metrics.OverlappingBlocks.Inc()
   761→				overlapping = true
   762→				level.Info(logger).Log("msg", "Found overlapping blocks during compaction", "ulid", meta.ULID)
   763→			}
   764→			if b.Meta().MaxTime > globalMaxt {
   765→				globalMaxt = b.Meta().MaxTime
   766→			}
   767→		}
   768→
   769→		indexr, err := b.Index()
   770→		if err != nil {
   771→			return fmt.Errorf("open index reader for block %+v: %w", b.Meta(), err)
   772→		}
   773→		closers = append(closers, indexr)
   774→
   775→		chunkr, err := b.Chunks()
   776→		if err != nil {
   777→			return fmt.Errorf("open chunk reader for block %+v: %w", b.Meta(), err)
   778→		}
   779→		closers = append(closers, chunkr)
   780→
   781→		tombsr, err := b.Tombstones()
   782→		if err != nil {
   783→			return fmt.Errorf("open tombstone reader for block %+v: %w", b.Meta(), err)
   784→		}
   785→		closers = append(closers, tombsr)
   786→
   787→		k, v := index.AllPostingsKey()
   788→		all, err := indexr.Postings(ctx, k, v)
   789→		if err != nil {
   790→			return err
   791→		}
   792→		all = indexr.SortedPostings(all)
   793→		// Blocks meta is half open: [min, max), so subtract 1 to ensure we don't hold samples with exact meta.MaxTime timestamp.
   794→		sets = append(sets, NewBlockChunkSeriesSet(b.Meta().ULID, indexr, chunkr, tombsr, all, meta.MinTime, meta.MaxTime-1, false))
   795→		syms := indexr.Symbols()
   796→		if i == 0 {
   797→			symbols = syms
   798→			continue
   799→		}
   800→		symbols = NewMergedStringIter(symbols, syms)
   801→	}
   802→
   803→	for symbols.Next() {
   804→		if err := indexw.AddSymbol(symbols.At()); err != nil {
   805→			return fmt.Errorf("add symbol: %w", err)
   806→		}
   807→	}
   808→	if err := symbols.Err(); err != nil {
   809→		return fmt.Errorf("next symbol: %w", err)
   810→	}
   811→
   812→	var (
   813→		ref      = storage.SeriesRef(0)
   814→		chks     []chunks.Meta
   815→		chksIter chunks.Iterator
   816→	)
   817→
   818→	set := sets[0]
   819→	if len(sets) > 1 {
   820→		// Merge series using specified chunk series merger.
   821→		// The default one is the compacting series merger.
   822→		set = storage.NewMergeChunkSeriesSet(sets, mergeFunc)
   823→	}
   824→
   825→	// Iterate over all sorted chunk series.
   826→	for set.Next() {
   827→		select {
   828→		case <-ctx.Done():
   829→			return ctx.Err()
   830→		default:
   831→		}
   832→		s := set.At()
   833→		chksIter = s.Iterator(chksIter)
   834→		chks = chks[:0]
   835→		for chksIter.Next() {
   836→			// We are not iterating in streaming way over chunk as
   837→			// it's more efficient to do bulk write for index and
   838→			// chunk file purposes.
   839→			chks = append(chks, chksIter.At())
   840→		}
   841→		if err := chksIter.Err(); err != nil {
   842→			return fmt.Errorf("chunk iter: %w", err)
   843→		}
   844→
   845→		// Skip the series with all deleted chunks.
   846→		if len(chks) == 0 {
   847→			continue
   848→		}
   849→
   850→		if err := chunkw.WriteChunks(chks...); err != nil {
   851→			return fmt.Errorf("write chunks: %w", err)
   852→		}
   853→		if err := indexw.AddSeries(ref, s.Labels(), chks...); err != nil {
   854→			return fmt.Errorf("add series: %w", err)
   855→		}
   856→
   857→		meta.Stats.NumChunks += uint64(len(chks))
   858→		meta.Stats.NumSeries++
   859→		for _, chk := range chks {
   860→			meta.Stats.NumSamples += uint64(chk.Chunk.NumSamples())
   861→		}
   862→
   863→		for _, chk := range chks {
   864→			if err := chunkPool.Put(chk.Chunk); err != nil {
   865→				return fmt.Errorf("put chunk: %w", err)
   866→			}
   867→		}
   868→		ref++
   869→	}
   870→	if err := set.Err(); err != nil {
   871→		return fmt.Errorf("iterate compaction set: %w", err)
   872→	}
   873→
   874→	return nil
   875→}
