   356→func printBlocks(blocks []tsdb.BlockReader, writeHeader, humanReadable bool) {
   357→	tw := tabwriter.NewWriter(os.Stdout, 13, 0, 2, ' ', 0)
   358→	defer tw.Flush()
   359→
   360→	if writeHeader {
   361→		fmt.Fprintln(tw, "BLOCK ULID	MIN TIME	MAX TIME	DURATION	NUM SAMPLES	NUM CHUNKS	NUM SERIES	SIZE")
   362→	}
   363→
   364→	for _, b := range blocks {
   365→		meta := b.Meta()
   366→
   367→		fmt.Fprintf(tw,
   368→			"%v	%v	%v	%v	%v	%v	%v	%v
",
   369→			meta.ULID,
   370→			getFormatedTime(meta.MinTime, humanReadable),
   371→			getFormatedTime(meta.MaxTime, humanReadable),
   372→			time.Duration(meta.MaxTime-meta.MinTime)*time.Millisecond,
   373→			meta.Stats.NumSamples,
   374→			meta.Stats.NumChunks,
   375→			meta.Stats.NumSeries,
   376→			getFormatedBytes(b.Size(), humanReadable),
   377→		)
   378→	}
   379→}
   380→
   381→func getFormatedTime(timestamp int64, humanReadable bool) string {
   382→	if humanReadable {
   383→		return time.Unix(timestamp/1000, 0).UTC().String()
   384→	}
   385→	return strconv.FormatInt(timestamp, 10)
   386→}
   387→
   388→func getFormatedBytes(bytes int64, humanReadable bool) string {
   389→	if humanReadable {
   390→		return units.Base2Bytes(bytes).String()
   391→	}
   392→	return strconv.FormatInt(bytes, 10)
   393→}
