  1034→// ApplyConfig applies a new config to the DB.
  1035→// Behaviour of 'OutOfOrderTimeWindow' is as follows:
  1036→// OOO enabled = oooTimeWindow > 0. OOO disabled = oooTimeWindow is 0.
  1037→// 1) Before: OOO disabled, Now: OOO enabled =>
  1038→//   - A new WBL is created for the head block.
  1039→//   - OOO compaction is enabled.
  1040→//   - Overlapping queries are enabled.
  1041→//
  1042→// 2) Before: OOO enabled, Now: OOO enabled =>
  1043→//   - Only the time window is updated.
  1044→//
  1045→// 3) Before: OOO enabled, Now: OOO disabled =>
  1046→//   - Time Window set to 0. So no new OOO samples will be allowed.
  1047→//   - OOO WBL will stay and will be eventually cleaned up.
  1048→//   - OOO Compaction and overlapping queries will remain enabled until a restart or until all OOO samples are compacted.
  1049→//
  1050→// 4) Before: OOO disabled, Now: OOO disabled => no-op.
  1051→func (db *DB) ApplyConfig(conf *config.Config) error {
  1052→	oooTimeWindow := int64(0)
  1053→	if conf.StorageConfig.TSDBConfig != nil {
  1054→		oooTimeWindow = conf.StorageConfig.TSDBConfig.OutOfOrderTimeWindow
  1055→	}
  1056→	if oooTimeWindow < 0 {
  1057→		oooTimeWindow = 0
  1058→	}
  1059→
  1060→	// Create WBL if it was not present and if OOO is enabled with WAL enabled.
  1061→	var wblog *wlog.WL
  1062→	var err error
  1063→	switch {
  1064→	case db.head.wbl != nil:
  1065→		// The existing WBL from the disk might have been replayed while OOO was disabled.
  1066→		wblog = db.head.wbl
  1067→	case !db.oooWasEnabled.Load() && oooTimeWindow > 0 && db.opts.WALSegmentSize >= 0:
  1068→		segmentSize := wlog.DefaultSegmentSize
  1069→		// Wal is set to a custom size.
  1070→		if db.opts.WALSegmentSize > 0 {
  1071→			segmentSize = db.opts.WALSegmentSize
  1072→		}
  1073→		oooWalDir := filepath.Join(db.dir, wlog.WblDirName)
  1074→		wblog, err = wlog.NewSize(db.logger, db.registerer, oooWalDir, segmentSize, db.opts.WALCompression)
  1075→		if err != nil {
  1076→			return err
  1077→		}
  1078→	}
  1079→
  1080→	db.opts.OutOfOrderTimeWindow = oooTimeWindow
  1081→	db.head.ApplyConfig(conf, wblog)
  1082→
  1083→	if !db.oooWasEnabled.Load() {
  1084→		db.oooWasEnabled.Store(oooTimeWindow > 0)
  1085→	}
  1086→	return nil
  1087→}
